@startuml

class MainActivity {
  ~ camera
  ~ duration
  --
  - showActiveMeasurement()
  - hideActiveMeasurement()
  - createMeasurement()
  - showResult()
}

class ResultActivity {
  ~ Measurement
  --
  - displayResult()
  - backToMainActivity()
  # onCreate()
}

class File {
}

class ImageFile {
  ~ File image
  --
  - cropImage() : void
  - toValue() : float[]
}

class Measurement {
  ~ camera
  ~ int[] redValues
  ~ int imgPerSecond
  --
  - captureImage() : ImageFile
  + start() : void
  - analyzeImage(imageFile) : int
  - calculateREsult(): int
}

File <|-- ImageFile

@enduml
